<%# app/views/posts/show.html.erb %>

<article class="blog-post">
  <header class="blog-post__header">
    <h1 class="blog-post__title"><%= h @post.title %></h1>
    <p class="blog-post__meta">
      <span class="blog-post__author"><%= h @post.user.name %></span>
      <span class="blog-post__date"><%= l @post.created_at, format: :long %></span>
    </p>
  </header>

  <section class="blog-post__content">
    <%= raw @post.content %>
  </section>
</article>